   369	template <typename AdapterType>
   370	ASTResult UnifiedASTBackend::ParseToASTResultTemplated(const AdapterType *adapter, const string &content,
   371	                                                       const string &language, const string &file_path,
   372	                                                       int32_t peek_size, const string &peek_mode) {
