   374		ExtractionConfig config;
   375		config.peek_size = peek_size;
   376	
   377		// Map legacy peek_mode to PeekLevel
   378		if (peek_mode == "none") {
   379			config.peek = PeekLevel::NONE;
   380		} else if (peek_mode == "smart") {
   381			config.peek = PeekLevel::SMART;
   382		} else if (peek_mode == "full") {
   383			config.peek = PeekLevel::FULL;
   384		} else if (peek_mode == "compact") {
   385			config.peek = PeekLevel::SMART; // Map compact to smart
   386		} else {
   387			config.peek = PeekLevel::SMART; // Default
   388		}
